e:12px;color:var(--muted);text-align:center;padding:8px">背包为空</div>')+'<div class="ns-title pink">私密档案</div><div class="text-block"><div class="kv-row"><span style="color:var(--muted)">发情度 / 常识崩坏度</span><span class="kv-v"><span style="color:var(--danger)">'+(secret.发情度||0)+'</span> / <span style="color:var(--pink)">'+(secret.常识崩坏度||0)+'</span></span></div><div class="kv-row"><span style="color:var(--muted)">体温 / 体液分泌</span><span class="kv-v">'+(secret.体温||'-')+' / '+(secret.体液分泌||'-')+'</span></div><div class="kv-row"><span style="color:var(--muted)">身体反应</span><span class="kv-v">'+(secret.身体反应||'-')+'</span></div><div class="kv-row"><span style="color:var(--muted)">隐藏性癖</span><span class="kv-v" style="color:var(--pink)">'+(secret.隐藏性癖||'-')+'</span></div><div class="kv-row"><span style="color:var(--muted)">生理周期 / 受孕率</span><span class="kv-v">'+(secret.生理周期||'-')+' / '+(secret.受孕概率||0)+'%</span></div></div><div class="ns-title pink">器官状态</div><div class="npc-grid">'+partsHtml+'</div></div></div>'}nc.innerHTML=html}

window.picUpload=function(npcName){var input=document.createElement('input');input.type='file';input.accept='image/*';input.onchange=function(e){var file=e.target.files[0];if(!file)return;var reader=new FileReader();reader.onload=function(ev){window.npcImageCache[npcName]=ev.target.result;try{localStorage.setItem('zzz_npc_bg_'+npcName,ev.target.result)}catch(e){}renderAll()};reader.readAsDataURL(file)};input.click()};
window.resetNpcBg=function(npcName){if(confirm('确定要重置 ['+npcName+'] 的底图吗？')){delete window.npcImageCache[npcName];try{localStorage.removeItem('zzz_npc_bg_'+npcName)}catch(e){}renderAll()}};
window.delNpc=function(npcName){if(confirm('确定要移除NPC ['+npcName+'] 吗？')){if(typeof triggerSlash==='function')triggerSlash('/send 请移除NPC ['+npcName+']|/trigger')}};
window.closeModal=function(){document.getElementById('overlay').classList.remove('show');document.getElementById('pickModal').classList.remove('show')};
window.showPickModal=function(title,items,callback){document.getElementById('pickTitle').textContent=title;var html='';if(items.length===0)html='<div class="nodata">暂无可用选项</div>';else items.forEach(function(it,i){html+='<div class="pick-item" onclick="selectPick('+i+')"><div class="pick-name">'+it.name+'</div><div class="pick-desc">'+(it.desc||'')+'</div></div>'});document.getElementById('pickList').innerHTML=html;window._pickItems=items;window.currentPickCallback=callback;document.getElementById('overlay').classList.add('show');document.getElementById('pickModal').classList.add('show')};
window.selectPick=function(idx){window.closeModal();if(window.currentPickCallback)window.currentPickCallback(window._pickItems[idx])};
document.querySelectorAll('.tab-btn').forEach(function(btn){btn.addEventListener('click',function(){document.querySelectorAll('.tab-btn').forEach(function(b){b.classList.remove('active')});document.querySelectorAll('.tab-panel').forEach(function(p){p.classList.remove('active')});btn.classList.add('active');document.getElementById('tab-'+btn.dataset.tab).classList.add('active')})});
function loadNpcBgCache(npcs){if(!npcs)return;try{for(var i=0;i<localStorage.length;i++){var k=localStorage.key(i);if(k.startsWith('zzz_npc_bg_')){var npcName=k.replace('zzz_npc_bg_','');if(npcs[npcName]!==undefined)window.npcImageCache[npcName]=localStorage.getItem(k)}}}catch(e){}}
function clearNpcBgCache(){window.npcImageCache={};try{var keysToRemove=[];for(var i=0;i<localStorage.length;i++){var k=localStorage.key(i);if(k.startsWith('zzz_npc_bg_'))keysToRemove.push(k)}keysToRemove.forEach(function(k){localStorage.removeItem(k)})}catch(e){}}

